 1	import React, { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
 5	import CloneTemplateModal from '@kubevirt-utils/components/CloneTemplateModal/CloneTemplateModal';
 6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { getTemplateProviderName } from '@kubevirt-utils/resources/template';
 9	import { getOperatingSystemName } from '@kubevirt-utils/resources/vm/utils/operation-system/operationSystem';
10	import { Alert, AlertVariant, Button, ButtonVariant } from '@patternfly/react-core';
11	
12	type CommonTemplateAlertProps = {
13	  template: V1Template;
14	};
15	
16	const CommonTemplateAlert: FC<CommonTemplateAlertProps> = ({ template }) => {
17	  const { t } = useKubevirtTranslation();
18	  const osName = getOperatingSystemName(template);
19	  const providerName = getTemplateProviderName(template);
20	  const { createModal } = useModal();
21	  const navigate = useNavigate();
22	
23	  const goToTemplatePage = React.useCallback(
24	    (clonedTemplate: V1Template) => {
25	      navigate(
26	        `/k8s/ns/${clonedTemplate.metadata.namespace}/templates/${clonedTemplate.metadata.name}`,
27	      );
28	    },
29	    [navigate],
30	  );
31	
32	  return (
33	    <Alert
34	      title={t('Templates provided by {{providerName}} are not editable.', {
35	        providerName,
36	      })}
37	      className="alert-margin-top-bottom template-header-alert"
38	      data-test="common-template-alert"
39	      isInline
40	      variant={AlertVariant.info}
41	    >
42	      {t(
43	        '{{ osName }} VirtualMachine can not be edited because it is provided by OpenShift Virtualization Operator.',
44	        { osName },
45	      )}
46	      <br />
47	
48	      {t('We suggest you to create a custom Template from this {{ providerName }} Template.', {
49	        providerName,
50	      })}
51	      <div className="margin-top">
52	        <Button
53	          onClick={() =>
54	            createModal(({ isOpen, onClose }) => (
55	              <CloneTemplateModal
56	                isOpen={isOpen}
57	                obj={template}
58	                onClose={onClose}
59	                onTemplateCloned={goToTemplatePage}
60	              />
61	            ))
62	          }
63	          variant={ButtonVariant.link}
64	        >
65	          {t('Create a new custom Template')}
66	        </Button>
67	      </div>
68	    </Alert>
69	  );
70	};
71	
72	export default CommonTemplateAlert;

